parameters.jsCode:
const item = $input.item.json;

// Determine image source type and build vision API payload
const hasBase64 = !!(item.screenshotBase64 && item.screenshotBase64.length > 100);
const hasUrl = !!(item.screenshotUrl && item.screenshotUrl.startsWith('http'));

let imageSource = null;
if (hasBase64) {
  imageSource = {
    type: 'base64',
    mediaType: item.imageMediaType || 'image/png',
    data: item.screenshotBase64
  };
} else if (hasUrl) {
  imageSource = {
    type: 'url',
    url: item.screenshotUrl
  };
}

// Map platform to descriptive profile
const platformProfiles = item.platformProfiles || {};
const platformDescription = platformProfiles[item.targetPlatform] || item.targetPlatform || 'web application';

// Build the OpenAI vision message payload
const visionPayload = {
  model: 'gpt-4o',
  max_tokens: 4096,
  messages: [
    {
      role: 'user',
      content: [
        {
          type: 'text',
          text: `You are an expert UX auditor. Analyze this screenshot of a ${platformDescription} and evaluate it against the 10 Nielsen Norman Heuristics, WCAG 2.1 accessibility guidelines, and platform-specific usability standards.\n\nReturn ONLY a valid JSON object in exactly this structure:\n{\n  "uiClassification": "string (e.g. login screen, dashboard, product page, onboarding, settings)",\n  "platformDetected": "string",\n  "heuristicScores": {\n    "visibility_of_system_status": { "score": 0, "finding": "string", "suggestion": "string" },\n    "match_real_world": { "score": 0, "finding": "string", "suggestion": "string" },\n    "user_control": { "score": 0, "finding": "string", "suggestion": "string" },\n    "consistency_standards": { "score": 0, "finding": "string", "suggestion": "string" },\n    "error_prevention": { "score": 0, "finding": "string", "suggestion": "string" },\n    "recognition_over_recall": { "score": 0, "finding": "string", "suggestion": "string" },\n    "flexibility_efficiency": { "score": 0, "finding": "string", "suggestion": "string" },\n    "aesthetic_minimalist": { "score": 0, "finding": "string", "suggestion": "string" },\n    "error_recovery": { "score": 0, "finding": "string", "suggestion": "string" },\n    "help_documentation": { "score": 0, "finding": "string", "suggestion": "string" },\n    "accessibility_wcag": { "score": 0, "finding": "string", "suggestion": "string" }\n  },\n  "topIssues": [\n    { "issue": "string", "severity": "CRITICAL|MAJOR|MINOR", "heuristic": "string", "actionablefix": "string", "estimatedEffort": "LOW|MEDIUM|HIGH" }\n  ],\n  "positivefindings": ["string"],\n  "overallNotes": "string"\n}\n\nScore each heuristic 0–10 where 0 = severe violation, 10 = fully satisfies the heuristic. List at least 5 top issues. Be specific and reference visible UI elements.`
        },
        hasBase64
          ? { type: 'image_url', image_url: { url: `data:${item.imageMediaType || 'image/png'};base64,${item.screenshotBase64}` } }
          : { type: 'image_url', image_url: { url: item.screenshotUrl } }
      ]
    }
  ]
};

return {
  json: {
    ...item,
    imageSource,
    platformDescription,
    visionPayload
  }
};

const item = $input.item.json;

// Extract raw AI response text
const rawContent = item.choices?.[0]?.message?.content || item.output || item.text || '{}';
const clean = rawContent.replace(/```json|```/g, '').trim();

let aiResult = {};
try {
  aiResult = JSON.parse(clean);
} catch(e) {
  aiResult = {
    uiClassification: 'unknown',
    platformDetected: item.targetPlatform || 'web',
    heuristicScores: {},
    topIssues: [],
    positiveFindings: [],
    overallNotes: 'AI parse error: ' + e.message
  };
}

return {
  json: {
    ...item,
    aiResult
  }
};

const item = $input.item.json;
const ai = item.aiResult || {};
const weights = item.heuristicWeights || {};
const severityLevels = item.severityLevels || {};
const thresholds = item.scoreThresholds || { excellent: 85, good: 70, needs_improvement: 50, poor: 0 };
const scores = ai.heuristicScores || {};

// Heuristic display labels
const heuristicLabels = {
  visibility_of_system_status: 'Visibility of System Status',
  match_real_world: 'Match Between System and Real World',
  user_control: 'User Control & Freedom',
  consistency_standards: 'Consistency & Standards',
  error_prevention: 'Error Prevention',
  recognition_over_recall: 'Recognition Over Recall',
  flexibility_efficiency: 'Flexibility & Efficiency of Use',
  aesthetic_minimalist: 'Aesthetic & Minimalist Design',
  error_recovery: 'Help Users Recognize & Recover from Errors',
  help_documentation: 'Help & Documentation',
  accessibility_wcag: 'Accessibility (WCAG 2.1)'
};

// Build scored heuristics array
const scoredHeuristics = Object.entries(scores).map(([key, val]) => {
  const score = typeof val === 'object' ? (val.score ?? 5) : (val ?? 5);
  const finding = typeof val === 'object' ? val.finding : '';
  const suggestion = typeof val === 'object' ? val.suggestion : '';
  const weight = weights[key] || 0.09;

  let severityLabel = 'GOOD';
  for (const [level, cfg] of Object.entries(severityLevels)) {
    if (score >= cfg.min && score <= cfg.max) { severityLabel = cfg.label; break; }
  }

  return {
    key,
    label: heuristicLabels[key] || key,
    score,
    weight,
    weightedScore: +(score * weight).toFixed(4),
    severity: severityLabel,
    finding: finding || '',
    suggestion: suggestion || ''
  };
});

// Weighted overall UX score (scale 0–100)
const totalWeight = scoredHeuristics.reduce((s, h) => s + h.weight, 0) || 1;
const rawWeighted = scoredHeuristics.reduce((s, h) => s + h.weightedScore, 0);
const overallUXScore = +((rawWeighted / totalWeight) * 10).toFixed(1);

// Grade
let grade = 'F';
if (overallUXScore >= thresholds.excellent) grade = 'A';
else if (overallUXScore >= thresholds.good) grade = 'B';
else if (overallUXScore >= thresholds.needs_improvement) grade = 'C';
else if (overallUXScore >= 30) grade = 'D';

// Verdict label
let verdict = 'Poor UX — Immediate Redesign Required';
if (grade === 'A') verdict = 'Excellent UX — Minor Polish Recommended';
else if (grade === 'B') verdict = 'Good UX — Targeted Improvements Needed';
else if (grade === 'C') verdict = 'Needs Improvement — Key Issues to Address';
else if (grade === 'D') verdict = 'Significant UX Problems — Prioritize Fixes';

// Critical / major / minor counts from top issues
const issues = ai.topIssues || [];
const criticalCount = issues.filter(i => i.severity === 'CRITICAL').length;
const majorCount = issues.filter(i => i.severity === 'MAJOR').length;
const minorCount = issues.filter(i => i.severity === 'MINOR').length;

// Sort issues by severity priority
const severityOrder = { CRITICAL: 1, MAJOR: 2, MINOR: 3 };
const sortedIssues = [...issues].sort((a, b) => (severityOrder[a.severity] || 9) - (severityOrder[b.severity] || 9));

// Category breakdown (worst heuristics first)
const heuristicsSorted = [...scoredHeuristics].sort((a, b) => a.score - b.score);

const report = {
  auditId: item.auditId,
  projectName: item.projectName,
  auditedAt: new Date().toISOString(),
  submittedAt: item.submittedAt,
  uiClassification: ai.uiClassification || 'Unknown',
  platformDetected: ai.platformDetected || item.targetPlatform,
  screenshotUrl: item.screenshotUrl || '(base64 upload)',

  overallUXScore,
  grade,
  verdict,

  issueSummary: { critical: criticalCount, major: majorCount, minor: minorCount, total: issues.length },
  heuristicBreakdown: heuristicsSorted,
  topIssues: sortedIssues,
  positiveFindings: ai.positiveFindings || ai.positivefindings || [],
  overallNotes: ai.overallNotes || '',

  worstHeuristic: heuristicsSorted[0]?.label || 'N/A',
  worstScore: heuristicsSorted[0]?.score ?? 'N/A',
  bestHeuristic: heuristicsSorted[heuristicsSorted.length - 1]?.label || 'N/A',
  bestScore: heuristicsSorted[heuristicsSorted.length - 1]?.score ?? 'N/A',

  recipientEmail: item.recipientEmail,
  status: 'Completed'
};

return { json: { ...item, report } };

parameters.text:
=You are a senior UX writer and consultant. Based on the structured heuristic audit data below, write a clear, professional, executive-ready UX improvement summary.

## Audit Results
Project: {{ $json.report.projectName }}
UI Type: {{ $json.report.uiClassification }}
Platform: {{ $json.report.platformDetected }}
Overall UX Score: {{ $json.report.overallUXScore }}/100 (Grade: {{ $json.report.grade }})
Verdict: {{ $json.report.verdict }}

## Issue Counts
Critical: {{ $json.report.issueSummary.critical }}
Major: {{ $json.report.issueSummary.major }}
Minor: {{ $json.report.issueSummary.minor }}

## Top Issues
{{ JSON.stringify($json.report.topIssues, null, 2) }}

## Positive Findings
{{ JSON.stringify($json.report.positiveFindings, null, 2) }}

## Heuristic Notes
{{ $json.report.overallNotes }}

Write a structured improvement report with these sections:
1. **Executive Summary** (2–3 sentences)
2. **Critical Issues to Fix First** (numbered list, each with what to fix and why it matters)
3. **Quick Wins** (low-effort, high-impact fixes)
4. **What's Working Well** (acknowledge strengths)
5. **Recommended Next Steps** (prioritized 30/60/90 day roadmap)

Tone: Direct, constructive, actionable. Use plain language, not jargon.

parameters.jsCode:
const item = $input.item.json;

const narrativeText = item.output || item.response || item.text || 'Report generation unavailable.';

return {
  json: {
    ...item,
    report: {
      ...item.report,
      narrativeReport: narrativeText
    }
  }
};

